import { useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

export default function Login() {

  const nav = useNavigate();

  const [email, setEmail] = useState("");

  const [password, setPassword] =
    useState("");

  const [role, setRole] =
    useState("customer");


  const loginUser = async (e) => {

    e.preventDefault();

    try {

      const res = await axios.post(
        "http://localhost:5000/api/auth/login",
        {
          email,
          password,
          role
        }
      );

      localStorage.setItem(
        "user",
        JSON.stringify(res.data.user)
      );

      // REDIRECT

      if (role === "customer") {

        nav("/customer-dashboard");

      } else {

        nav("/labour-dashboard");
      }

    } catch (err) {

      alert("Invalid Credentials");
    }
  };

  return (

    <div style={styles.page}>

      <div style={styles.card}>

        {/* LOGO */}

        <h1 style={styles.logo}>
          DailyMajdoor
        </h1>

        <p style={styles.subtext}>
          Login to continue
        </p>

        {/* FORM */}

        <form onSubmit={loginUser}>

          <select
            style={styles.input}
            value={role}
            onChange={(e) =>
              setRole(e.target.value)
            }
          >
            <option value="customer">
              Customer
            </option>

            <option value="labour">
              Labour
            </option>

          </select>

          <input
            type="email"
            placeholder="Email"
            style={styles.input}
            value={email}
            onChange={(e) =>
              setEmail(e.target.value)
            }
          />

          <input
            type="password"
            placeholder="Password"
            style={styles.input}
            value={password}
            onChange={(e) =>
              setPassword(e.target.value)
            }
          />

          <button style={styles.button}>
            Login
          </button>

        </form>

        <p style={styles.bottomText}>

          Don't have an account?

          <span
            style={styles.link}
            onClick={() =>
              nav("/register")
            }
          >
            Register
          </span>

        </p>

      </div>

    </div>
  );
}

const styles = {

  page: {
    minHeight: "100vh",
    background: "#f4f7fb",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    fontFamily: "Arial"
  },

  card: {
    width: "380px",
    background: "white",
    padding: "40px",
    borderRadius: "18px",
    boxShadow:
      "0 4px 15px rgba(0,0,0,0.05)"
  },

  logo: {
    textAlign: "center",
    color: "#2563eb",
    marginBottom: "10px",
    fontSize: "28px"
  },

  subtext: {
    textAlign: "center",
    color: "#6b7280",
    marginBottom: "30px",
    fontSize: "14px"
  },

  input: {
    width: "100%",
    padding: "14px",
    marginBottom: "18px",
    borderRadius: "10px",
    border: "1px solid #d1d5db",
    fontSize: "14px",
    outline: "none",
    boxSizing: "border-box"
  },

  button: {
    width: "100%",
    padding: "14px",
    background: "#2563eb",
    color: "white",
    border: "none",
    borderRadius: "10px",
    cursor: "pointer",
    fontSize: "15px",
    fontWeight: "500"
  },

  bottomText: {
    textAlign: "center",
    marginTop: "22px",
    color: "#6b7280",
    fontSize: "14px"
  },

  link: {
    color: "#2563eb",
    marginLeft: "6px",
    cursor: "pointer",
    fontWeight: "500"
  }

};
